using namespace std;
struct Obiect {
    double g, v, rap;
};
bool cmp(Obiect a, Obiect b) {
    return a.rap > b.rap;
}
int main() {
    int n; double gCap;
    if (cin >> n >> gCap) {
        Obiect o[100];
        for (int i=0; i<n; i++) {
            cin >> o[i].g >> o[i].v;
            o[i].rap = o[i].v / o[i].g;
        }
        sort(o, o+n, cmp);
        double valTot = 0;
        for (int i=0; i<n; i++) {
            if (gCap >= o[i].g) {
                valTot += o[i].v;
                gCap -= o[i].g;
            } else {
                valTot += gCap * o[i].rap;
                break;
            }
        }
        cout << fixed << setprecision(2) << valTot << endl;
    }
    return 0;
}

