#include <iostream>
using namespace std;
int v[1000], temp[1000];
void merge_arr(int st, int mij, int dr) {
    int i = st, j = mij + 1, k = st;
    while (i <= mij && j <= dr) {
        if (v[i] <= v[j]) temp[k++] = v[i++];
        else temp[k++] = v[j++];
    }
    while (i <= mij) temp[k++] = v[i++];
    while (j <= dr) temp[k++] = v[j++];
    for (i = st; i <= dr; i++) v[i] = temp[i];
}
void merge_sort(int st, int dr) {
    if (st < dr) {
        int mij = st + (dr - st) / 2;
        merge_sort(st, mij);
        merge_sort(mij + 1, dr);
        merge_arr(st, mij, dr);
    }
}
int main() {
    int n;
    if (cin >> n) {
        for(int i=0; i<n; i++) cin >> v[i];
        merge_sort(0, n - 1);
        for(int i=0; i<n; i++) cout << v[i] << " ";
        cout << endl;
    }
    return 0;
}

