#include <iostream>
using namespace std;
const int INF = 1e9;
int n, m;
int cost[101][101];
int dist[101];
bool viz[101];
int main() {
    if (!(cin >> n >> m)) return 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (i == j) cost[i][j] = 0;
            else cost[i][j] = INF;
        }
    }
    for (int i = 0; i < m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        cost[u][v] = w;
    }
    for (int i = 1; i <= n; i++) {
        dist[i] = cost[1][i];
        viz[i] = false;
    }
    dist[1] = 0;
    viz[1] = true;
    for (int k = 1; k < n; k++) {
        int minNod = -1, minVal = INF;
        for (int i = 1; i <= n; i++) {
            if (!viz[i] && dist[i] < minVal) {
                minVal = dist[i];
                minNod = i;
            }
        }
        if (minNod == -1) break;
        viz[minNod] = true;
        for (int i = 1; i <= n; i++) {
            if (!viz[i] && dist[minNod] + cost[minNod][i] < dist[i]) {
                dist[i] = dist[minNod] + cost[minNod][i];
            }
        }
    }
    for (int i = 1; i <= n; i++) {
        if (dist[i] == INF) cout << -1 << " ";
