#include <iostream>
#include <algorithm>
using namespace std;
struct Muchie {
    int u, v, w;
};
bool cmp(Muchie a, Muchie b) { return a.w < b.w; }
int tata[101];
int gaseste(int x) {
    if (tata[x] == 0) return x;
    return tata[x] = gaseste(tata[x]);
}
bool reuneste(int x, int y) {
    int rx = gaseste(x);
    int ry = gaseste(y);
    if (rx != ry) {
        tata[rx] = ry;
        return true;
    }
    return false;
}
int main() {
    int n, m;
    if (cin >> n >> m) {
        Muchie e[1000];
        for (int i = 0; i < m; i++) {
            cin >> e[i].u >> e[i].v >> e[i].w;
        }
        sort(e, e+m, cmp);
        int costTot = 0, muchiiSelectate = 0;
        for (int i = 0; i < m; i++) {
            if (reuneste(e[i].u, e[i].v)) {
                costTot += e[i].w;
                muchiiSelectate++;
                if (muchiiSelectate == n - 1) break;
            }
        }
        cout << costTot << endl;
    }
    return 0;
}

